settings.customCss:
.mfdr-table{width:100%;border-collapse:collapse;font-size:13px;background:#fff}
.mfdr-table thead th{background:#1f3a52;color:#fff;text-align:center;padding:9px 8px;font-weight:600;font-size:12px;text-transform:uppercase;letter-spacing:.5px;border:0}
.mfdr-table tbody td{padding:8px;text-align:center;border-bottom:1px solid #eaeef0}
.mfdr-table tbody tr:hover{background:#f5f9fa;cursor:pointer}
.mfdr-table tbody td:nth-child(1){font-weight:700;color:#0a5d3a;width:50px}
.mfdr-table tbody td:nth-child(2){text-align:left;font-weight:600;color:#0070c0;text-decoration:underline;text-decoration-color:rgba(0,112,192,.3)}
.mfdr-table tbody tr:hover td:nth-child(2){text-decoration-color:#0070c0}
.mfdr-group{margin-bottom:14px;border:1px solid #d6dde0;border-radius:6px;overflow:hidden}
.mfdr-group-header{background:linear-gradient(180deg,#f7f9fa 0%,#eef2f4 100%);padding:9px 14px;font-weight:700;color:#1f3a52;font-size:14px;border-bottom:1px solid #d6dde0;cursor:pointer;user-select:none}
.mfdr-group-header:hover{background:#eaf0f3}
.mfdr-group-collapsed .mfdr-group-body{display:none}
.mfdr-detail-row{background:#fafbfc}
.mfdr-detail-content{padding:14px}
.mfgs-round{margin-bottom:12px;border:1px solid #d6dde0;border-radius:5px;overflow:hidden}
.mfgs-round-hdr{background:linear-gradient(180deg,#f7f9fa 0%,#eef2f4 100%);padding:8px 12px;font-size:13px;border-bottom:1px solid #d6dde0;cursor:pointer}
.mfgs-round-hdr strong{color:#1f3a52}
.mfgs-round-hdr em{color:#5a6a72;font-style:italic;margin-left:8px;font-weight:normal}
.mfgs-arrow{display:inline-block;margin-right:6px;transition:transform .2s}
.mfgs-toggle.mfgs-open .mfgs-arrow{transform:rotate(90deg)}
.mfgs-slope{padding:5px 12px;background:#fff;font-size:11px;color:#5a6a72;border-bottom:1px solid #eaeef0}
.mfgs-hidden{display:none}
.mfgs-table{width:100%;border-collapse:collapse;font-size:12px}
.mfgs-table th,.mfgs-table td{padding:5px 4px;text-align:center;border:1px solid #eaeef0}
.mfgs-table th{background:#f0f4f6;color:#1f3a52;font-weight:600}
.mfgs-sep{background:#f7f9fa;font-weight:600}
.mfgs-yardage td{color:#6a7a82;font-size:10px}
.mfgs-par-row td{background:#fafbfc;font-weight:600;color:#1f3a52}
.mfgs-si-row td{color:#8a9aa2;font-size:10px}
.mfgs-player-label{text-align:left !important;font-weight:600;color:#0070c0}
.mfgs-mark{display:inline-flex;align-items:center;justify-content:center;width:22px;height:22px;font-weight:700;line-height:1}
.mfgs-eagle{background:#0a5d3a;color:#fff;border-radius:50%;box-shadow:0 0 0 2px #fff,0 0 0 3px #0a5d3a}
.mfgs-birdie{color:#c0392b;border:1.5px solid #c0392b;border-radius:50%}
.mfgs-par{color:#1f3a52}
.mfgs-bogey{color:#0070c0;border:1.5px solid #0070c0}
.mfgs-dblbogey{color:#0070c0;border:1.5px solid #0070c0;box-shadow:0 0 0 1px #fff,0 0 0 2px #0070c0}
.mfgs-total{background:#1f3a52 !important;color:#fff !important}
